(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[8862],{3121:(n,s,a)=>{"use strict";a.r(s),a.d(s,{data:()=>e});const e={key:"v-49fc5eef",path:"/python/loop/while/",title:"ลูป While",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"วิธีการใช้ WHILE loop",slug:"วิธีการใช้-while-loop",children:[]},{level:2,title:"Infinite Loop",slug:"infinite-loop",children:[]},{level:2,title:"คำสั่งอื่นๆที่เกี่ยวข้อง (Break & Continue)",slug:"คําสั่งอื่นๆที่เกี่ยวข้อง-break-continue",children:[{level:3,title:"Using break",slug:"using-break",children:[]},{level:3,title:"Using continue",slug:"using-continue",children:[]}]}],filePathRelative:"python/loop/while/README.md",git:{updatedTime:162676698e4,contributors:[]}}},8926:(n,s,a)=>{"use strict";a.r(s),a.d(s,{default:()=>p});const e=(0,a(6252).uE)('<h1 id="ลูป-while" tabindex="-1"><a class="header-anchor" href="#ลูป-while" aria-hidden="true">#</a> ลูป While</h1><p>ลูปประเภท <code>WHILE</code> ก็คือการ <strong>วนเมื่อเงื่อนไขยังคงถูกต้อง</strong> และจะทำการหยุดเมื่อเงื่อนไขไม่เป็นจริงแล้ว หากน้องยังไม่เข้าใจก็ให้อ่านใหม่ครับ แต่ถ้าเข้าใจแล้วก็อ่านเรื่องต่อไปได้เลย</p><p>!&gt; <strong>คำแนะนำ</strong><br> เนื่องจากว่าอันนี้มันง่ายที่สุด พี่เลยแนะนำว่าให้มาลองเล่นอันนี้ให้่ชำนาญก่อนนะครับ ก่อนที่จะไปหา Loop อีกประเภทนึง</p><h2 id="วิธีการใช้-while-loop" tabindex="-1"><a class="header-anchor" href="#วิธีการใช้-while-loop" aria-hidden="true">#</a> วิธีการใช้ WHILE loop</h2><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code><span class="token keyword">while</span> <span class="token operator">&lt;</span>arguments<span class="token operator">&gt;</span><span class="token punctuation">:</span>\n    <span class="token comment"># และจะรันโค้ดด้านล่างเมื่อ &lt;argument&gt; ยังเป็นจริง</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>ตัวอย่างเช่น</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>count <span class="token operator">=</span> <span class="token number">10</span>\n<span class="token keyword">while</span> count <span class="token operator">&gt;</span> <span class="token number">5</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span>count<span class="token punctuation">,</span> end<span class="token operator">=</span><span class="token string">&quot; &quot;</span><span class="token punctuation">)</span>\n    count <span class="token operator">=</span> count <span class="token operator">-</span> <span class="token number">1</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>ก็จะได้ค่าออกมาเป็น</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>10 9 8 7 6\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="infinite-loop" tabindex="-1"><a class="header-anchor" href="#infinite-loop" aria-hidden="true">#</a> Infinite Loop</h2><p><img src="http://3.bp.blogspot.com/_F7vpRIjAvYI/TIU7VpNlbzI/AAAAAAAABoI/s2clJ4LoWO0/s1600/image.png" alt=""></p><p>น้องอาจจะยังไม่เข้าใจว่า Infinite Loop คืออะไร<br> 1 Infinite Loop เป็นบ้านของ Apple ครับ<br></p><p>หยอกๆ Infinite Loop ก็คือ Loop ที่ัยังไม่จบนั่นเอง<br> เนื่องจากอะไรนั่นเหรอ ก็เพราะว่าเงื่อนไขยังไม่เป็นจริงซักทียังไงหล่ะ มันก็เลยเกิด</p><p>และเมื่อเกิดแล้ว น้องก็จะหยุดมันไม่ได้ครับ ยกเว้นว่าต้องทำการหยุดด้วยการ Terminate โปรแกรม</p><p>เอาเป็นว่าไปดูตัวอย่างดีกว่าครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token string">&quot;cute&quot;</span>\n<span class="token keyword">while</span> <span class="token punctuation">(</span>kumamon <span class="token operator">=</span> <span class="token string">&quot;cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n  <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;You are in an infinite loop&quot;</span><span class="token punctuation">)</span>\n\n<span class="token comment"># Returns</span>\nYou are <span class="token keyword">in</span> an infinite loop\nYou are <span class="token keyword">in</span> an infinite loop\nYou are <span class="token keyword">in</span> an infinite loop\nYou are <span class="token keyword">in</span> an infinite loop\n<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>\n<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>\n<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>\n<span class="token punctuation">.</span><span class="token punctuation">.</span><span class="token punctuation">.</span>\n<span class="token comment"># แล้วมันไม่หยุดเลยครับ จริงๆนะ</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><p>ถ้าสังเกตดีๆ บรรทัดแรกพี่ได้ประกาศตัวแปร kumamon ให้เท่ากับ &quot;cute&quot; มันก็ไม่มีอะไรแปลกประหลาด บรรทัดที่ 2 พี่ได้เขียนว่า &quot;เมื่อตัวแปร kumamon เท่ากับ &quot;cute&quot; แล้วก็จะให้วน loop&quot; ก็ไม่แปลกอะไร แล้ว loop ก็เรื่มครับ เพราะว่าเป็นจริง</p><p>แต่ว่า ไม่มีบรรทัดไหนมีการเปลี่ยนตัวแปร kumamon เลย ทำให้ &quot;เมื่อตัวแปร kumamon เท่ากับ &quot;cute&quot; แล้วก็จะให้วน loop&quot; ยังคงเป็นจริงอยู่ ทำให้วนอยู่แบบนี้แหละครับ ไม่มีใครหยุดมันเลย</p><h2 id="คําสั่งอื่นๆที่เกี่ยวข้อง-break-continue" tabindex="-1"><a class="header-anchor" href="#คําสั่งอื่นๆที่เกี่ยวข้อง-break-continue" aria-hidden="true">#</a> คำสั่งอื่นๆที่เกี่ยวข้อง (Break &amp; Continue)</h2><p>เนื่องจากว่า น้องต้องการทำ loop แต่ก็อยากที่จะข้าม หรือหยุด loop เมื่อถึงเงื่อนไขที่น้องตั้งเพื่มขึ้นมานั่นเอง<br> ใน lecture นี้ก็จะสอน keyword ทืี่น้องเอาไว้คุม loop 2 อัน นั่นก็คือ</p><ul><li>Break</li><li>Continue</li></ul><h3 id="using-break" tabindex="-1"><a class="header-anchor" href="#using-break" aria-hidden="true">#</a> Using break</h3><p>เป็น keyword ที่ว่า เมื่อ loop ถึงบรรทัด break นี้ได้ก็จะทำการออก loop นั้นทันที</p><p>!&gt; <strong>ข้อระวัง</strong><br>ออกแค่ใน loop ที่ตัวเองอยู่ หากว่าอยู่ใน loop ซ้อน loop ก็จะออก loop ที่ตัวเองอยู่ แต่ไม่ได้ออก loop ที่วนอยู่ภายนอก</p><p>ตัวอย่างการใช้ <code>break</code></p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>kumamon <span class="token operator">=</span> <span class="token string">&quot;cute&quot;</span>\nage <span class="token operator">=</span> <span class="token number">21</span>\n\n<span class="token keyword">while</span> <span class="token punctuation">(</span>kumamon <span class="token operator">==</span> <span class="token string">&quot;cute&quot;</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n    <span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;I am happy&quot;</span><span class="token punctuation">)</span>\n    age <span class="token operator">+=</span> <span class="token number">1</span>\n\n    <span class="token keyword">if</span> <span class="token punctuation">(</span>age <span class="token operator">==</span> <span class="token number">25</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n        <span class="token keyword">break</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>ก็จะออกผลมาว่า</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>I am happy\nI am happy\nI am happy\nI am happy\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>เพราะได้วน 4 รอบ แต่ทำไมวนได้ 4 รอบหล่ะ</p><p>รอบแรกค่า age = 21 และก็ได้เพื่มในบรรทัดที่ 6 เป็น 22 ครับ และบรรทัดที่ 8 ก็ไม่เป็นจริง เพราะว่า 22 ไม่เท่ากับ 25 ครับ<br> รอบที่ 2 ก็เช่่นกัน age = 22 และก็ได้เพื่มในบรรทัดที่ 6 เป็น 23 ครับ และบรรทัดที่ 8 ก็ไม่เป็นจริง เพราะว่า 23 ไม่เท่ากับ 25 ครับ</p><p>วนไปถึงรอบที่ 4 age = 24 และก็ได้เพื่มในบรรทัดที่ 6 เป็น 25 ครับ และบรรทัดที่ 8 ก็เป็นจริง เพราะว่า 25 เท่ากับ 25 แล้ว จึงถึงบรรทัดที่มี <code>break</code> ได้ ทำให้โปรแกรมออกจาก loop มานั่นเอง</p><h3 id="using-continue" tabindex="-1"><a class="header-anchor" href="#using-continue" aria-hidden="true">#</a> Using continue</h3><p>โดยตัว continue นั้นมีความแตกต่างกับ break อยู่นิดเดียว นั่นก็คือ หากถึงบรรทัดนั่นแล้ว ก็จะกลับไปรัน loop ใหม่ โดยทำให้ข้ามบรรทัดที่จะทำงานหลังมันทันที</p><p>ถ้ายังไม่เข้าใจก็ไปดูกันครับ</p><div class="language-python ext-py line-numbers-mode"><pre class="language-python"><code>i <span class="token operator">=</span> <span class="token number">0</span>\n<span class="token keyword">while</span> <span class="token punctuation">(</span>true<span class="token punctuation">)</span><span class="token punctuation">:</span>\n    i <span class="token operator">+=</span> <span class="token number">1</span>\n    <span class="token keyword">if</span> <span class="token punctuation">(</span>i <span class="token operator">==</span> <span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">:</span>\n        <span class="token keyword">continue</span>\n\n    <span class="token keyword">print</span><span class="token punctuation">(</span>i<span class="token punctuation">,</span> end<span class="token operator">=</span><span class="token string">&quot; &quot;</span><span class="token punctuation">)</span> <span class="token comment"># ในบรรทัดนี้ พี่มงได้ใส่ parameter `end = &quot; &quot;` เข้าไปด้วย เพื่อให้มันปรี้นท์ &quot; &quot; แทนบรรทัดใหม่ครับ</span>\n\n<span class="token keyword">print</span><span class="token punctuation">(</span><span class="token string">&quot;Loop is complete!&quot;</span><span class="token punctuation">)</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>ก็จะแสดงผลออกมาดังนี้ครับ</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>&quot;0 1 2 3 4 6 7 8 9 Loop is complete!&quot;\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>น้องก็จะเห็นว่า พอ i = 5 แล้ว ก็จะไม่รันโค้ดด้านล่างเลย (บรรทัดที่ 7 เป็นต้นไป)<br> แต่เนื่องจากว่าบรรทัดที่ 9 นั้นไม่ได้อยู่ใน loop เลยรันได้อย่างปกติดี</p><p>พี่ก็เลยทำสรุปเอาไว้สำหรับ break และ continue ดังนี้ครับ</p><table><thead><tr><th></th><th><strong>break</strong></th><th><strong>continue</strong></th></tr></thead><tbody><tr><td><strong>เพื่อเอาไว้</strong></td><td>หยุด loop</td><td>เรื่ม loop ใหม่ทันที</td></tr><tr><td><strong>มีหน้าที่หลักคือ</strong></td><td>เพื่อเอาไว้กัน infinite loop</td><td>เพื่อหยุดให้ loop ทำงานในส่วนที่ไม่เกี่ยวข้อง</td></tr></tbody></table>',40),p={render:function(n,s){return e}}}}]);